def process_graph(graph_data):

    def get_port_capacity(port_node):
        return port_node[1].get('physical_capacity_bps', 0)

    def calculate_node_capacity(graph, node_name):
        # Find the node in the graph with matching name
        target_node = None
        for n in graph.nodes(data=True):
            if n[1].get('name') == node_name:
                target_node = n
                break

        if not target_node:
            return 0

        # Traverse down to find all PORTs under this node
        total_capacity = 0
        queue = [target_node]
        visited = set()

        while queue:
            current = queue.pop(0)
            current_name = current[1]['name']

            if current_name in visited:
                continue
            visited.add(current_name)

            # If it's a PORT, add its capacity
            if 'EK_PORT' in current[1]['type']:
                total_capacity += get_port_capacity(current)
            else:
                # Continue traversing children via edges
                for successor in graph.successors(current_name):
                    edge_data = graph.get_edge_data(current_name, successor)
                    if edge_data and edge_data.get('type') == 'RK_CONTAINS':
                        succ_node = (successor, dict(graph.nodes[successor]))
                        queue.append(succ_node)

        return total_capacity

    # Create a copy of the graph to avoid modifying the original
    graph_copy = graph_data.copy()

    # Find the control domain node with name 'ju1.a4.dom'
    control_domain_node = None
    for node in graph_copy.nodes(data=True):
        if node[1].get('name') == 'ju1.a4.dom' and 'EK_CONTROL_DOMAIN' in node[1]['type']:
            control_domain_node = node
            break

    if not control_domain_node:
        return_object = {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }
        return return_object

    # Get all direct children of the control domain node
    children = []
    control_domain_name = control_domain_node[1]['name']
    for successor in graph_copy.successors(control_domain_name):
        edge_data = graph_copy.get_edge_data(control_domain_name, successor)
        if edge_data and edge_data.get('type') == 'RK_CONTAINS':
            child_node = (successor, dict(graph_copy.nodes[successor]))
            children.append(child_node)

    # Calculate capacity for each child
    child_capacities = []
    for child in children:
        child_name = child[1]['name']
        capacity = calculate_node_capacity(graph_copy, child_name)
        child_capacities.append((child_name, capacity))

    # Sort by capacity descending
    child_capacities.sort(key=lambda x: x[1], reverse=True)

    # Prepare return object
    return_object = {
        'type': 'list',
        'data': child_capacities,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

    return return_object

