    agg_block_node = None
    if superblock_node:
        for u, v, edge_attrs in graph_copy.edges(data=True):
            if u == superblock_node and edge_attrs.get('type') == 'RK_CONTAINS' and 'EK_AGG_BLOCK' in graph_copy.nodes[v].get('type', []):
                agg_block_node = v
                break

    # Find chassis contained in this agg_block
    chassis_nodes = []
    if agg_block_node:
        for u, v, edge_attrs in graph_copy.edges(data=True):
            if u == agg_block_node and edge_attrs.get('type') == 'RK_CONTAINS' and 'EK_CHASSIS' in graph_copy.nodes[v].get('type', []):
                chassis_nodes.append(v)

    # Find the first chassis to add the new packet switch to
    chassis_to_add = chassis_nodes[0] if chassis_nodes else None

